package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import static org.junit.jupiter.api.Assertions.assertEquals;

public class CSVFormatTest {

    @Test
    public void testGetTrailingDelimiter() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        boolean result = csvFormat.getTrailingDelimiter();

        // Then
        assertEquals(false, result);
    }

    @Test
    public void testGetTrailingDelimiterWithMock() throws Exception {
        // Given
        CSVFormat csvFormat = Mockito.spy(CSVFormat.DEFAULT);
        Mockito.doReturn(true).when(csvFormat).getTrailingDelimiter();

        // When
        boolean result = csvFormat.getTrailingDelimiter();

        // Then
        assertEquals(true, result);
    }
}
